const aiOutput = $input.first().json.output || '';

const match = aiOutput.match(/\[CHARTS_JSON\]([\s\S]*?)\[\/CHARTS_JSON\]/);
if (!match) {
  return [{ json: { error: 'No CHARTS_JSON block found', rawOutput: aiOutput.slice(-1200) } }];
}

let raw = match[1].trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

let charts;
try {
  charts = JSON.parse(raw);
} catch (e) {
  const repaired = raw.replace(/,\s*([\]\}])/g, '$1');
  try {
    charts = JSON.parse(repaired);
  } catch (e2) {
    return [{ json: { error: 'Failed to parse CHARTS_JSON: ' + e2.message, rawJson: raw.slice(0, 1200) } }];
  }
}

if (!Array.isArray(charts) || charts.length === 0) {
  return [{ json: { error: 'CHARTS_JSON is empty or not an array' } }];
}

return charts
  .filter(c => c && c.chartConfig && c.chartConfig.data)
  .map(c => ({ json: { sheetName: c.sheetName || 'chart', chartConfig: c.chartConfig } }));

// Attach sheetName to binary data
const allItems  = $input.all();
const allCharts = $('Parse AI Chart Configs1').all();

return allItems.map((item, idx) => {
  const sheetName = allCharts[idx]?.json?.sheetName || ('chart_' + idx);
  return { json: { sheetName }, binary: item.binary };
});

// Convert binary PNG to base64 for GitHub API
const item = $input.first();
const sheetName = item.json.sheetName;
const binaryKey = Object.keys(item.binary || {})[0] || 'data';
const binaryData = item.binary?.[binaryKey];

if (!binaryData) {
  return [{ json: { error: 'No binary data found', sheetName } }];
}

// n8n stores binary as base64 in binaryData.data
const base64Content = binaryData.data;
const fileName = sheetName + '.png';
const githubPath = 'dashboard/charts/' + fileName;

return [{ json: { sheetName, fileName, githubPath, base64Content } }];

// Merge SHA from GET response with chart data for PUT
const getResponse = $input.first().json;
const prevNode = $('PNG to Base64').first().json;

const sha = getResponse?.sha || null;

return [{
  json: {
    sheetName: prevNode.sheetName,
    fileName: prevNode.fileName,
    githubPath: prevNode.githubPath,
    base64Content: prevNode.base64Content,
    sha
  }
}];

