// Build the sanity_check.json payload for GitHub
const analysis = $input.first().json.output || '';
const date = new Date().toISOString().slice(0, 10);

const chartNames = [
  'demand_global',
  'demand_transaction',
  'ranking_global_war',
  'demand_asset',
  'audience'
];

const titles = {
  demand_global: 'Global Search Demand',
  demand_transaction: 'Transaction Segments',
  ranking_global_war: 'SEO WAR Ranking',
  demand_asset: 'Demand by Asset Type',
  audience: 'Audience Split'
};

const payload = {
  generatedAt: date,
  analysis: analysis,
  charts: chartNames.map(name => ({
    name,
    title: titles[name] || name,
    file: name + '.png'
  }))
};

const jsonString = JSON.stringify(payload, null, 2);
const base64Content = Buffer.from(jsonString, 'utf-8').toString('base64');

return [{ json: { base64Content, githubPath: 'dashboard/data/sanity_check.json', date } }];

